// Remap binary field from Form Trigger output to 'data' for Extract From File
const items = $input.all();
const result = [];
for (const item of items) {
  const binary = item.binary || {};
  if (binary['data']) {
    // Already has 'data' field, pass through as-is
    result.push({ json: item.json, binary });
  } else if (binary['Assignment Brief']) {
    // Remap the expected Form Trigger field to 'data'
    result.push({ json: item.json, binary: { data: binary['Assignment Brief'] } });
  } else {
    // Fallback: try the first available binary field
    const keys = Object.keys(binary);
    if (keys.length === 0) {
      throw new Error('No file was uploaded. Please upload a PDF, DOCX, or TXT file.');
    }
    result.push({ json: item.json, binary: { data: binary[keys[0]] } });
  }
}
return result;

// Consolidate extracted text from any upload format (PDF, DOCX, TXT)
const items = $input.all();
let briefText = '';

for (const item of items) {
  if (item.json.text) {
    briefText += item.json.text + '\n';
  }
}

if (!briefText.trim()) {
  throw new Error('No text could be extracted from the uploaded file. Please ensure the file contains readable text.');
}

return [{ json: { briefText: briefText.trim() } }];

// Parse the Anthropic extraction response into structured JSON
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || '';

let responseText = '';
if (Array.isArray(rawResponse)) {
  responseText = rawResponse.map(b => b.text || '').join('');
} else {
  responseText = String(rawResponse);
}

const jsonMatch = responseText.match(/```json\s*([\s\S]*?)```/) || responseText.match(/\{[\s\S]*\}/);
let extraction = {};
try {
  extraction = JSON.parse(jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : responseText);
} catch(e) {
  extraction = { rawText: responseText, parseError: e.message };
}

const briefText = $input.first().json.briefText || '';
return [{ json: { extraction, briefText } }];

// Parse the structure generation response
const rawResponse = $input.first().json.message?.content
  || $input.first().json.response
  || $input.first().json.text
  || '';

let responseText = '';
if (Array.isArray(rawResponse)) {
  responseText = rawResponse.map(b => b.text || '').join('');
} else {
  responseText = String(rawResponse);
}

const jsonMatch = responseText.match(/```json\s*([\s\S]*?)```/) || responseText.match(/\{[\s\S]*\}/);
let structure = {};
try {
  structure = JSON.parse(jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : responseText);
} catch(e) {
  structure = { rawText: responseText };
}

const genericSections = ['introduction', 'conclusion', 'literature review', 'analysis', 'discussion'];
if (structure.sections) {
  structure.sections = structure.sections.filter(s => {
    const title = (s.title || '').toLowerCase();
    return !genericSections.some(g => title === g);
  });
}

const prevData = $input.first().json;
return [{ json: { ...prevData, structure } }];

// Parse the written content
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || '';

let responseText = '';
if (Array.isArray(rawResponse)) {
  responseText = rawResponse.map(b => b.text || '').join('');
} else {
  responseText = String(rawResponse);
}

const prevData = $input.first().json;
return [{ json: { ...prevData, writtenContent: responseText } }];

// Parse the enhanced content from Anthropic
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || '';

let responseText = '';
if (Array.isArray(rawResponse)) {
  responseText = rawResponse.map(b => b.text || '').join('');
} else {
  responseText = String(rawResponse);
}

const prevData = $input.first().json;
return [{ json: { ...prevData, enhancedContent: responseText, iterationCount: 0 } }];

// Parse validation results and determine if refinement is needed
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || '';

let responseText = '';
if (Array.isArray(rawResponse)) {
  responseText = rawResponse.map(b => b.text || '').join('');
} else {
  responseText = String(rawResponse);
}

const jsonMatch = responseText.match(/```json\s*([\s\S]*?)```/) || responseText.match(/\{[\s\S]*\}/);
let validation = {};
try {
  validation = JSON.parse(jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : responseText);
} catch(e) {
  validation = { score: 85, requiresRefinement: false };
}

const prevData = $input.first().json;
const requiresRefinement = (validation.score || 85) < 80;
const iterationCount = (prevData.iterationCount || 0) + 1;

return [{ json: { ...prevData, validation, requiresRefinement, iterationCount } }];

// Parse refined content and loop back for re-validation
const rawResponse = $input.first().json.message?.content
  || (typeof $input.first().json.response === 'object' ? JSON.stringify($input.first().json.response) : $input.first().json.response)
  || $input.first().json.text
  || '';

let responseText = '';
if (Array.isArray(rawResponse)) {
  responseText = rawResponse.map(b => b.text || '').join('');
} else {
  responseText = String(rawResponse);
}

const prevData = $input.first().json;
return [{ json: { ...prevData, enhancedContent: responseText } }];

// Generate the final HTML document for download
const data = $input.first().json;
const content = data.enhancedContent;
const extraction = data.extraction;
const structure = data.structure;

const title = extraction?.assignmentTitle || 'Academic Assignment';
const student = extraction?.studentName || '';
const date = new Date().toLocaleDateString('en-GB', { year: 'numeric', month: 'long', day: 'numeric' });

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${title}</title>
<style>
  body { font-family: 'Times New Roman', serif; font-size: 12pt; line-height: 1.6; margin: 0; padding: 0; color: #000; }
  .cover { page-break-after: always; display: flex; flex-direction: column; align-items: center; justify-content: center; min-height: 100vh; text-align: center; padding: 60px; }
  .cover h1 { font-size: 24pt; margin-bottom: 20px; }
  .cover p { font-size: 14pt; margin: 8px 0; }
  .content { margin: 60px; }
  h2 { font-size: 16pt; margin-top: 40px; }
  h3 { font-size: 13pt; margin-top: 24px; }
  p { text-align: justify; margin: 12px 0; }
  .references { margin-top: 40px; border-top: 1px solid #000; padding-top: 20px; }
  @media print { body { margin: 0; } .content { margin: 25mm; } }
</style>
</head>
<body>
<div class="cover">
  <h1>${title}</h1>
  ${student ? `<p><strong>Student:</strong> ${student}</p>` : ''}
  <p><strong>Date:</strong> ${date}</p>
</div>
<div class="content">
${content}
</div>
</body>
</html>`;

const fileName = title.replace(/[^a-z0-9]/gi, '_').toLowerCase() + '_assignment.html';

return [{ json: { fileName, data: Buffer.from(html).toString('base64'), mimeType: 'text/html', title } }];

